import React, { useEffect, useState, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useSelector } from 'react-redux';
import { NODE_API, ENDPOINTS } from '../api/config';
import { nodeApi } from '../api/axios';
import { toast } from 'react-toastify';
import './Portfolio.css';

const Portfolio = () => {
  const { userId } = useParams();
  const navigate = useNavigate();
  const { user } = useSelector((state) => state.auth);
  const isOwn = !userId || userId === user?._id;

  const [tab, setTab] = useState('images'); // images, videos
  const [images, setImages] = useState([]);
  const [videos, setVideos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [uploading, setUploading] = useState(false);
  const [selectedItems, setSelectedItems] = useState([]);
  const [previewItem, setPreviewItem] = useState(null);

  const getImageUrl = (path) => {
    if (!path) return null;
    if (path.startsWith('http')) return path;
    return `${NODE_API}/${path}`;
  };

  const loadPortfolio = useCallback(async () => {
    setLoading(true);
    try {
      const response = await nodeApi.post('/api/v1/post/getMyPortfolio', {
        skip: 0, limit: 0,
        ...(isOwn ? {} : { userId }),
      });
      const items = response.data?.data?.myPortolio || response.data?.data || [];
      const imgs = items.filter((item) => {
        const url = item?.mediaURL?.original || item?.mediaURL || '';
        return !url.toLowerCase().includes('.mp4');
      });
      const vids = items.filter((item) => {
        const url = item?.mediaURL?.original || item?.mediaURL || '';
        return url.toLowerCase().includes('.mp4');
      });
      setImages(imgs);
      setVideos(vids);
    } catch (error) {
      toast.error('Failed to load portfolio');
    }
    setLoading(false);
  }, [isOwn, userId]);

  useEffect(() => {
    loadPortfolio();
  }, [loadPortfolio]);

  const handleUpload = async (e, type) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (file.size > 10 * 1024 * 1024) {
      toast.warn('File must be under 10MB');
      return;
    }
    setUploading(true);
    try {
      const formData = new FormData();
      formData.append('mediaFile0', file);
      await nodeApi.post(ENDPOINTS.CREATE_PORTFOLIO, formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
      });
      toast.success(`${type === 'video' ? 'Video' : 'Image'} uploaded!`);
      loadPortfolio();
    } catch (error) {
      toast.error('Upload failed');
    }
    setUploading(false);
  };

  const handleDelete = async (portfolioId) => {
    if (!window.confirm('Delete this item?')) return;
    try {
      await nodeApi.post('/api/v1/post/deleteMyPortfolio', { portfolioId: portfolioId.toString() });
      toast.success('Deleted');
      loadPortfolio();
    } catch (error) {
      toast.error('Failed to delete');
    }
  };

  const toggleSelect = (itemId) => {
    setSelectedItems((prev) =>
      prev.includes(itemId) ? prev.filter((id) => id !== itemId) : [...prev, itemId].slice(0, 4)
    );
  };

  const currentItems = tab === 'images' ? images : videos;

  return (
    <div className="portfolio-page">
      {/* Header */}
      <div className="portfolio-header">
        <button className="portfolio-back" onClick={() => navigate(-1)}>←</button>
        <h1 className="portfolio-title">Photo Library</h1>
      </div>

      {/* Upload buttons (owner only) */}
      {isOwn && (
        <div className="portfolio-upload-btns">
          <label className="portfolio-upload-btn">
            📷 Add Image
            <input type="file" accept="image/*" onChange={(e) => handleUpload(e, 'image')} hidden disabled={uploading} />
          </label>
          <label className="portfolio-upload-btn">
            🎥 Add Video
            <input type="file" accept="video/*" onChange={(e) => handleUpload(e, 'video')} hidden disabled={uploading} />
          </label>
        </div>
      )}
      {uploading && <p className="portfolio-uploading">Uploading...</p>}

      {/* Tabs */}
      <div className="portfolio-tabs">
        <button className={`portfolio-tab ${tab === 'images' ? 'active' : ''}`} onClick={() => setTab('images')}>
          Images
        </button>
        <button className={`portfolio-tab ${tab === 'videos' ? 'active' : ''}`} onClick={() => setTab('videos')}>
          Videos
        </button>
      </div>

      {/* Grid */}
      <div className="portfolio-grid">
        {loading && <div className="groups-loading"><div className="page-loading-spinner" /></div>}
        {!loading && currentItems.length === 0 && (
          <div className="groups-empty"><p>No {tab} yet</p></div>
        )}
        {currentItems.map((item) => {
          const url = getImageUrl(item?.mediaURL?.original || item?.mediaURL?.thumbnail || item?.mediaURL);
          const thumbUrl = getImageUrl(item?.thumbnailURL?.original || item?.thumbnailURL);
          const itemId = item._id;
          const isSelected = selectedItems.includes(itemId);

          return (
            <div key={itemId} className="portfolio-cell" onClick={() => setPreviewItem(item)}>
              <img
                src={tab === 'videos' ? (thumbUrl || url) : url}
                alt=""
                className="portfolio-cell-img"
              />
              {tab === 'videos' && (
                <span className="portfolio-play-icon">▶</span>
              )}
              {isOwn && (
                <>
                  <button
                    className="portfolio-delete-icon"
                    onClick={(e) => { e.stopPropagation(); handleDelete(itemId); }}
                  >
                    ✕
                  </button>
                  <button
                    className={`portfolio-select-icon ${isSelected ? 'selected' : ''}`}
                    onClick={(e) => { e.stopPropagation(); toggleSelect(itemId); }}
                  >
                    {isSelected ? '☑' : '☐'}
                  </button>
                </>
              )}
            </div>
          );
        })}
      </div>

      {/* Preview overlay */}
      {previewItem && (
        <div className="portfolio-preview-overlay" onClick={() => setPreviewItem(null)}>
          <img
            src={getImageUrl(previewItem?.mediaURL?.original || previewItem?.mediaURL)}
            alt=""
            className="portfolio-preview-img"
          />
          {isOwn && (
            <button
              className="portfolio-preview-delete"
              onClick={(e) => { e.stopPropagation(); handleDelete(previewItem._id); setPreviewItem(null); }}
            >
              Delete
            </button>
          )}
        </div>
      )}
    </div>
  );
};

export default Portfolio;
